INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e0e44cf6-4113-4559-a720-60c3f304d2d2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ollama Prompt Engineering — System Prompts, Few-Shot, CoT, and Structured Output$escape$,
  $escape$Ollama's /api/chat endpoint gives you full control over prompt structure via the messages array. Set behavior at inference time using a system role message — no fine-tuning needed. For few-shot prompting, prepend alternating user/assistant turns before your real query; Ollama passes the full context window to the model unchanged.

For chain-of-thought, append "Think step by step before answering." to your user message — models like llama3.2 and qwen2.5-coder respond well. Don't wrap CoT in the system prompt; it's more effective inline.

Structured output is handled via the format field. Pass format: { ...jsonSchema } (supported in Ollama ≥0.5) to constrain output to a JSON schema — no post-processing regex hacks. Older builds support format: "json" for untyped JSON mode. Combine with a system prompt that describes the schema fields for best results. Always set temperature: 0 when using structured output to reduce hallucinated keys. The options object on /api/chat accepts num_ctx to expand context if your few-shot examples are long.$escape$,
  $escape$import ollama

response = ollama.chat(
    model="llama3.2",
    messages=[
        {"role": "system", "content": "You extract structured data. Always respond with valid JSON matching the given schema."},
        {"role": "user", "content": "Repo: react. Stars: 220k. Lang: JavaScript."},
        {"role": "assistant", "content": "{\"name\": \"react\", \"stars\": 220000, \"language\": \"JavaScript\"}"},
        {"role": "user", "content": "Repo: rustlang/rust. Stars: 98k. Lang: Rust. Think step by step."}
    ],
    format={"type": "object", "properties": {"name": {"type": "string"}, "stars": {"type": "integer"}, "language": {"type": "string"}}, "required": ["name", "stars", "language"]},
    options={"temperature": 0, "num_ctx": 4096}
)
print(response['message']['content'])$escape$,
