INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c1b52d28-413a-4bd9-9ecc-76e413917da7',
  '00000000-0000-0000-0000-000000000001',
  $escape$ollama + Hugging Face Hub — Pull Any GGUF Model Directly, No Python Required$escape$,
  $escape$Ollama natively supports pulling GGUF models from Hugging Face Hub using the `hf.co/` namespace prefix — no manual download, no conversion scripts, no transformers environment. The entire HF community model ecosystem is one `ollama pull` away.

When a repo hosts multiple GGUF files, pin a specific quantization as the tag: `hf.co/bartowski/Llama-3.2-3B-Instruct-GGUF:Q4_K_M`. Omit the tag and ollama selects the most appropriate quantization automatically based on available VRAM.

Once pulled, the model lives in ollama's local registry and behaves identically to any first-party model — `ollama run`, the REST API at `localhost:11434/api/generate`, and any OpenAI-compatible client all work without changes. You can also use the `hf.co/` URI directly inside a `Modelfile`'s `FROM` instruction to layer a custom `SYSTEM` prompt, `PARAMETER` overrides, or a `TEMPLATE` on top of a community model — turning any HF GGUF into a versioned, reproducible ollama model without touching the transformers library or a tokenizer config.$escape$,
  $escape$# Pull directly from HF Hub — no Python, no git-lfs
ollama pull hf.co/bartowski/Llama-3.2-3B-Instruct-GGUF:Q4_K_M

# Wrap it in a Modelfile to customize behavior
cat > Modelfile <<'EOF'
FROM hf.co/bartowski/Llama-3.2-3B-Instruct-GGUF:Q4_K_M
SYSTEM "You are a terse, accurate coding assistant. Respond in plain text only."
PARAMETER temperature 0.2
PARAMETER num_ctx 8192
EOF

# Register as a named local model
ollama create my-coder -f Modelfile
ollama run my-coder "Explain Go defer in one paragraph"$escape$,
  $escape$bash$escape$,
