INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b1ed1757-037b-43af-bc7f-15a4f9868a7f',
  '00000000-0000-0000-0000-000000000001',
  $escape$ollama + LlamaIndex — Local RAG with Full Control Over Indexing and Retrieval$escape$,
  $escape$LlamaIndex integrates with Ollama via `Ollama` LLM and `OllamaEmbedding` classes, letting you run the entire RAG pipeline locally — no API keys, no data leaving your machine. Pull your model first (`ollama pull llama3.2`), then point LlamaIndex at it. For document loading, `SimpleDirectoryReader` handles PDFs, markdown, and text out of the box. Indexing strategy matters: `VectorStoreIndex` suits semantic search, while `SummaryIndex` works better for summarization-heavy queries. Under the hood, `OllamaEmbedding` with `nomic-embed-text` (768-dim) generates embeddings — always use a dedicated embedding model, not your chat model, for accuracy and speed. The `as_query_engine()` method wires retrieval directly to your local Ollama LLM. Tune `similarity_top_k` to control how many chunks are retrieved before synthesis. For production-quality retrieval, swap the default in-memory store for ChromaDB or pgvector and persist your index. Sentence-window chunking outperforms naive fixed-size splits for technical docs.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, SimpleDirectoryReader
from llama_index.llms.ollama import Ollama
from llama_index.embeddings.ollama import OllamaEmbedding
from llama_index.core import Settings

Settings.llm = Ollama(model="llama3.2", request_timeout=120.0)
Settings.embed_model = OllamaEmbedding(model_name="nomic-embed-text")

docs = SimpleDirectoryReader("./docs").load_data()
index = VectorStoreIndex.from_documents(docs)

query_engine = index.as_query_engine(similarity_top_k=5)
response = query_engine.query("How does attention mechanism work?")
print(response)$escape$,
  $escape$python$escape$,
