INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a184b66e-5bdd-47f4-b01e-a6ade96cf228',
  '00000000-0000-0000-0000-000000000001',
  $escape$ollama's OpenAI-Compatible API — Chat, Tools, Structured Output & Embeddings in One Server$escape$,
  $escape$ollama exposes a fully OpenAI-compatible REST layer at `http://localhost:11434/v1`, so you can drop in the `openai` Python SDK by just swapping the base URL — no extra dependencies. For chat completions, point `base_url` at localhost and set `api_key="ollama"` (any non-empty string). Function calling works with models that support tools (e.g. `llama3.1`, `mistral-nemo`) — pass `tools=` exactly as you would against the OpenAI API; ollama handles the tool-call marshalling locally. Structured outputs via `response_format={"type": "json_object"}` force JSON mode on any model, but for schema-strict output use `format="json"` in the native `/api/chat` endpoint instead. Embeddings hit `/v1/embeddings` with models like `nomic-embed-text` or `mxbai-embed-large` — pull them first with `ollama pull nomic-embed-text`. The entire stack runs offline; latency is your GPU, not a network hop.$escape$,
  $escape$from openai import OpenAI

client = OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")

# Chat completion
response = client.chat.completions.create(
    model="llama3.1",
    messages=[{"role": "user", "content": "What is RAG?"}],
)
print(response.choices[0].message.content)

# Embeddings
embed = client.embeddings.create(
    model="nomic-embed-text",
    input="semantic search query",
)
print(embed.data[0].embedding[:5])$escape$,
  $escape$python$escape$,
