INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9718edac-c7d2-4afc-adb8-22901943af99',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ollama Tool Use & Streaming — Claude API Primitives, Fully Local$escape$,
  $escape$Ollama's `/api/chat` endpoint supports the same three primitives you'd reach for in the Anthropic API: system prompts, tool use, and streaming — all running locally. System prompts slot into the `messages` array as `{"role": "system", "content": "..."}`, identical to Claude's format. Tool use landed in Ollama 0.3 and follows the OpenAI function-calling schema: declare tools as JSON schemas, and capable models like `llama3.2` or `mistral-nemo` emit structured `tool_calls` in the response message. Unlike Anthropic's API, Ollama's tool-result turn uses `role: "tool"` with a matching `tool_call_id` to continue the loop. Streaming is opt-in: pass `stream=True` to `ollama.chat()` in Python and iterate the generator — each chunk is a dict with `done: false` until the final chunk closes the stream. Critical caveat: tool use is model-dependent. Run `ollama show <model>` and confirm `tools` appears under the capabilities section before wiring up your tool loop, or you'll get unparsed plain-text responses instead of structured calls.$escape$,
  $escape$import ollama

stream = ollama.chat(
    model="llama3.2",
    messages=[
        {"role": "system", "content": "You are a precise code reviewer."},
        {"role": "user", "content": "Review src/auth.py for security issues"},
    ],
    tools=[{"type": "function", "function": {
        "name": "read_file",
        "description": "Read a file by path",
        "parameters": {"type": "object", "properties": {"path": {"type": "string"}}, "required": ["path"]},
    }}],
    stream=True,
)
for chunk in stream:
    msg = chunk["message"]
    print(msg.get("tool_calls") or msg["content"], end="", flush=True)$escape$,
  $escape$python$escape$,
