INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd9e9c003-ff59-434a-910d-daf158e6d8cf',
  '00000000-0000-0000-0000-000000000001',
  $escape$ollama → Groq: Drop-in Speed Upgrade via OpenAI-Compatible API$escape$,
  $escape$Ollama serves its OpenAI-compatible endpoint at `http://localhost:11434/v1`, which means any client already talking to Ollama can route to Groq with two variable changes. Groq's LPU delivers ~300–500 tokens/sec versus a typical local GPU at 30–80 tokens/sec — a 6–10× gap on the same model family.

Groq supports models that map directly to Ollama counterparts: `llama-3.3-70b-versatile` ↔ `llama3.3:70b`, `llama3-8b-8192` ↔ `llama3.2:8b`, `gemma2-9b-it` ↔ `gemma2:9b`. The API surface is identical — `/chat/completions`, streaming, system prompts — so no prompt engineering changes. The critical difference is model name format: Ollama uses `name:tag` (e.g. `mistral:7b`), Groq uses versioned slugs (`mixtral-8x7b-32768`). Use an environment flag to switch targets rather than hardcoding either URL, so you can benchmark both or fall back to local inference when offline.$escape$,
  $escape$import os
from openai import OpenAI

USE_GROQ = os.getenv("USE_GROQ", "false").lower() == "true"

client = OpenAI(
    base_url="https://api.groq.com/openai/v1" if USE_GROQ else "http://localhost:11434/v1",
    api_key=os.getenv("GROQ_API_KEY", "ollama"),
)

MODEL = "llama-3.3-70b-versatile" if USE_GROQ else "llama3.3:70b"

response = client.chat.completions.create(
    model=MODEL,
    messages=[{"role": "user", "content": "Explain GGUF quantization in 2 sentences."}],
    stream=False,
)
print(response.choices[0].message.content)$escape$,
  $escape$python$escape$,
