INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '592ebcb2-cba4-4b92-938b-a3eaa6936c94',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ollama — Run Local LLMs with Zero Data Leaving Your Machine$escape$,
  $escape$Ollama bundles model weights, runtime, and a REST API into a single process — no cloud account, no telemetry, no data egress. Pull a model once with `ollama pull llama3.2` and it's cached in `~/.ollama/models`. The built-in library covers 100+ models: Llama 3.2, Mistral, Gemma 2, Phi-3, Qwen2.5, DeepSeek-R1, and code-specific variants like `codellama` and `qwen2.5-coder`. Every model is content-addressed via a SHA256 manifest — identical to how Docker layers work.

The local HTTP server runs on `localhost:11434` and exposes `/api/generate` (streaming tokens) and `/api/chat` (OpenAI-compatible `/v1/chat/completions`). That OpenAI compatibility means you can drop Ollama behind any existing SDK by swapping the base URL. Quantized variants (Q4_K_M, Q8_0) let you right-size VRAM usage — `ollama show llama3.2 --modelfile` reveals the exact quant level and context length. For privacy-sensitive workloads — PII extraction, internal codebases, medical notes — this is the architecture: no tokens ever leave localhost.$escape$,
  $escape$import ollama

# Stream a response from a locally served model
stream = ollama.chat(
    model='llama3.2',
    messages=[{'role': 'user', 'content': 'Summarize this PII-heavy doc: John Doe, SSN 123-45-6789'}],
    stream=True,
)

for chunk in stream:
    print(chunk['message']['content'], end='', flush=True)

# Inspect loaded model metadata — quant level, context window, parameters
info = ollama.show('llama3.2')
print(info['modelinfo'])$escape$,
  $escape$python$escape$,
