INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b0f4c3ad-eac6-4828-b32b-b092a278e456',
  '00000000-0000-0000-0000-000000000001',
  $escape$ollama Fine-Tuning — LoRA, QLoRA, and When Your Modelfile Is Already Enough$escape$,
  $escape$Before reaching for fine-tuning, exhaust your Modelfile. A well-crafted SYSTEM instruction in ollama handles most formatting, persona, and domain-framing tasks at zero training cost — and swapping base models is a one-line change.

Fine-tune when: your task requires knowledge absent from the base model's weights (internal docs, proprietary schemas), you need consistent structured output that system prompts can't reliably lock in, or long context windows are creating latency you can't tolerate.

Ollama doesn't train — it serves. Your LoRA/QLoRA workflow lives outside: use Unsloth or Hugging Face PEFT against a base like Llama 3.2 or Mistral. QLoRA quantizes base weights to 4-bit during training, letting you fine-tune a 7B model on a single 24GB GPU. LoRA freezes the base and trains only small rank-decomposition matrices — fast and cheap.

Once done, merge the adapter into the base and export to GGUF via llama.cpp's convert scripts. Q4_K_M is the practical sweet spot for quality vs. speed. Drop the GGUF into a Modelfile with FROM pointing at the local file, run ollama create, and it's a first-class model in your local registry — indistinguishable from a pulled one.$escape$,
  $escape$# After QLoRA training + adapter merge, export to GGUF
python convert_hf_to_gguf.py ./merged-model --outtype q4_k_m --outfile model-q4km.gguf

# Modelfile — point ollama at your local GGUF
cat > Modelfile <<'EOF'
FROM ./model-q4km.gguf
SYSTEM "You are a specialist for internal API documentation. Reply only in structured JSON."
PARAMETER temperature 0.1
PARAMETER num_ctx 4096
EOF

# Register and run
ollama create internal-api-bot -f Modelfile
ollama run internal-api-bot "Describe the /auth/refresh endpoint"$escape$,
  $escape$bash$escape$,
