INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7d640fb0-5147-4a6f-98a1-e7723baef321',
  '00000000-0000-0000-0000-000000000001',
  $escape$ollama Agent Loops — Local Tool Use with llama3.1 and the ReAct Pattern$escape$,
  $escape$Ollama's tool use API (supported by llama3.1, mistral-nemo, and firefunction-v2) lets you run full agent loops entirely on-device. Pass a `tools` array to `ollama.chat()` with JSON Schema function definitions — the model returns structured `tool_calls` in the message when it decides to act.

The ReAct loop is explicit: send messages → check `message.tool_calls` → dispatch each call to real Python functions → append results as `role: "tool"` messages → repeat until the model returns a plain content response with no tool calls. No framework required.

Tool selection reliability is model-dependent. llama3.1:8b handles single-tool tasks well; for multi-step routing or parallel calls, llama3.1:70b or mistral-nemo:12b produces more consistent JSON. Always validate `tool_calls[n].function.name` before dispatching — smaller models occasionally hallucinate names outside your schema.

Keep descriptions sharp: one sentence per function, explicit `required` fields, no optional noise. Verbose schemas bloat the context window and degrade selection accuracy in models under 13B parameters.$escape$,
  $escape$import ollama

tools = [{
    "type": "function",
    "function": {
        "name": "get_stock_price",
        "description": "Get the current price for a stock ticker symbol",
        "parameters": {
            "type": "object",
            "properties": {"ticker": {"type": "string"}},
            "required": ["ticker"]
        }
    }
}]

def dispatch(name, args):
    if name == "get_stock_price":
        return {"ticker": args["ticker"], "price": 142.30}  # stub
    raise ValueError(f"Unknown tool: {name}")

def run_agent(prompt: str) -> str:
    messages = [{"role": "user", "content": prompt}]
    while True:
        res = ollama.chat(model="llama3.1", messages=messages, tools=tools)
        msg = res["message"]
        messages.append(msg)
        if not msg.get("tool_calls"):
            return msg["content"]
        for call in msg["tool_calls"]:
            result = dispatch(call["function"]["name"], call["function"]["arguments"])
            messages.append({"role": "tool", "content": str(result)})

print(run_agent("What is the price of AAPL?"))$escape$,
  $escape$python$escape$,
