INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fa86d264-faf1-443d-bf28-3a438fdb0845',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ollama Streaming — Token-by-Token Output with Python's AsyncGenerator$escape$,
  $escape$Ollama's `chat()` and `generate()` methods accept `stream=True`, returning a synchronous generator that yields response chunks as they arrive from the local model. Each chunk is a dict with a `message` key (for chat) containing a `content` delta — not the full string, just the new tokens. You accumulate them yourself.

The key UX win: first-token latency on a local llama3.2 model is ~200ms, but full response can be 10–30s. Streaming lets you flush output immediately rather than blocking the UI. For CLI tools, `print(chunk['message']['content'], end='', flush=True)` gives the typewriter effect. For web APIs, pipe chunks into an SSE or chunked HTTP response.

Watch for `chunk['done'] == True` — that's the terminal chunk containing `eval_count`, `eval_duration`, and `prompt_eval_count` for perf introspection. You lose these stats if you break early. For structured output use cases, buffer the full stream before JSON parsing — partial JSON will always fail validation.$escape$,
  $escape$import ollama

def stream_chat(prompt: str, model: str = "llama3.2") -> None:
    stream = ollama.chat(
        model=model,
        messages=[{"role": "user", "content": prompt}],
        stream=True,
    )
    for chunk in stream:
        print(chunk["message"]["content"], end="", flush=True)
        if chunk["done"]:
            print()  # newline after stream ends
            print(f"Tokens generated: {chunk['eval_count']}")
            print(f"Speed: {chunk['eval_count'] / (chunk['eval_duration'] / 1e9):.1f} tok/s")

stream_chat("Explain RLHF in 3 sentences")$escape$,
  $escape$python$escape$,
