INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cf5944d5-a241-461f-9290-4180884e51c7',
  '00000000-0000-0000-0000-000000000001',
  $escape$ollama Cost Management — GPU Time, Token Tracking, and Model Selection$escape$,
  $escape$Local inference with ollama shifts 'cost' from dollars to GPU time and memory pressure. The biggest lever is model selection: `llama3.2:3b-instruct-q4_K_M` runs 3× faster than `llama3.1:8b-instruct-q8_0` with acceptable quality for most tasks — pick the smallest quantization that meets your accuracy bar before over-provisioning.

Every `generate` and `chat` response includes `prompt_eval_count`, `eval_count`, and `eval_duration` nanoseconds for exact token accounting. Use these to detect prompt bloat before it compounds across thousands of requests.

Set `num_ctx` explicitly — it defaults to the model's full training context but linearly increases VRAM. For short-form tasks, `num_ctx: 2048` can free gigabytes. Pair this with a tuned `keep_alive`: raise it during active sessions to amortize the 2–4s model load cycle, or set `keep_alive: 0` after batch jobs to immediately reclaim VRAM.

For throughput, `num_batch` controls how many tokens are processed per GPU kernel call — larger values improve utilization on long prompts but add latency on short ones. Profile both with `eval_duration` before committing.$escape$,
  $escape$import ollama

response = ollama.generate(
    model="llama3.2:3b-instruct-q4_K_M",
    prompt="Summarize the CAP theorem in one paragraph.",
    options={
        "num_ctx": 2048,
        "num_batch": 512,
    },
    keep_alive="10m",
)

tokens_in  = response["prompt_eval_count"]
tokens_out = response["eval_count"]
ms_per_tok = response["eval_duration"] / 1e6 / tokens_out

print(f"prompt={tokens_in} gen={tokens_out} speed={ms_per_tok:.1f}ms/tok")$escape$,
  $escape$python$escape$,
