INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6cadf620-326d-4ea8-b48d-2bcfbf4ad709',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ollama Context Management — Sliding Windows, Chunking, and Summarization$escape$,
  $escape$Ollama exposes `num_ctx` in every `/api/chat` and `/api/generate` request via `options` — this controls the KV-cache window, not just input truncation. Set it per-request: `options={"num_ctx": 32768}` overrides the Modelfile default for that call only.

For long sessions, the `messages` array in `/api/chat` is your sliding window. Ollama reprocesses the full array each call — there is no server-side session state. When history exceeds your `num_ctx` budget (roughly 3–4 tokens per word), you must trim it yourself.

Two strategies combine well: **sliding window** drops the oldest non-system messages first, keeping the system prompt and recent turns intact. **Summarization** calls Ollama itself — use a lean model like `llama3.2:1b` to compress dropped turns into a new system message entry, preserving semantic continuity at low token cost.

For RAG-style chunking, split documents into ~512-token chunks with a 50-token overlap, embed via `ollama.embeddings()` using `nomic-embed-text`, then inject only the top-k chunks into `messages`. Never stuff full documents — Ollama's attention degrades at context extremes even within declared `num_ctx` limits.$escape$,
  $escape$import ollama

def summarize_history(messages: list) -> str:
    text = "\n".join(f"{m['role']}: {m['content']}" for m in messages)
    resp = ollama.chat("llama3.2:1b", messages=[
        {"role": "user", "content": f"Summarize in 2 sentences:\n{text}"}
    ], options={"num_ctx": 4096})
    return resp["message"]["content"]

def compress_and_chat(history: list, user_msg: str) -> str:
    if len(history) > 8:
        summary = summarize_history(history[:-2])
        history = [{"role": "system", "content": f"Prior context: {summary}"}] + history[-2:]
    history.append({"role": "user", "content": user_msg})
    resp = ollama.chat("llama3.2", messages=history, options={"num_ctx": 8192})
    history.append(resp["message"])
    return resp["message"]["content"]$escape$,
  $escape$python$escape$,
